<script setup lang="ts">
import { computed, onMounted, ref, watch } from "vue";
import AppAlert from "@/components/feedback/AppAlert.vue";
import PageContainer from "@/components/layout/PageContainer.vue";
import PageHeader from "@/components/layout/PageHeader.vue";
import { apiGet, apiRequest } from "@/api/client";

interface Bank { id: string; name: string; status: string; subject_id?: string }
interface Subject { id: string; code: string; name: string; status: string }
interface Question { id: string; content: string; difficulty: string | null; status: string; choices: { id: string; content: string; is_correct: boolean }[] }
const banks = ref<Bank[]>([]); const subjects = ref<Subject[]>([]); const questions = ref<Question[]>([]);
const bankForm = ref({ name: "", owner_org_unit_id: "", subject_id: "", is_shared: false });
const questionForm = ref({ content: "", difficulty: "medium", choices: [{ content: "", is_correct: true }, { content: "", is_correct: false }, { content: "", is_correct: false }, { content: "", is_correct: false }] });
const selectedBankId = ref(""); const message = ref(""); const error = ref("");
const selectedBank = computed(() => banks.value.find((bank) => bank.id === selectedBankId.value));
async function load() { [banks.value, subjects.value] = await Promise.all([apiGet<Bank[]>("/question-banks"), apiGet<Subject[]>("/question-banks/subjects")]); if (!selectedBankId.value && banks.value[0]) selectedBankId.value = banks.value[0].id; }
async function loadQuestions() { questions.value = selectedBankId.value ? await apiGet<Question[]>(`/question-banks/${selectedBankId.value}/questions`) : []; }
async function createBank() { error.value = ""; try { await apiRequest<Bank>("/question-banks", "POST", bankForm.value); message.value = "สร้างคลังข้อสอบแล้ว"; await load(); } catch (e) { error.value = e instanceof Error ? e.message : "สร้างคลังไม่สำเร็จ"; } }
async function createQuestion() { if (!selectedBankId.value) return; error.value = ""; try { await apiRequest(`/question-banks/${selectedBankId.value}/questions`, "POST", questionForm.value); message.value = "เพิ่มคำถามแล้ว"; questionForm.value.content = ""; questionForm.value.choices.forEach((choice) => { choice.content = ""; }); await loadQuestions(); } catch (e) { error.value = e instanceof Error ? e.message : "เพิ่มคำถามไม่สำเร็จ"; } }
async function publish(id: string) { await apiRequest<Bank>(`/question-banks/${id}/publish`, "POST"); message.value = "เผยแพร่คลังข้อสอบแล้ว"; await load(); }
watch(selectedBankId, loadQuestions); onMounted(load);
</script>
<template><PageContainer><PageHeader eyebrow="Exam Author" title="จัดการคลังข้อสอบ" description="สร้างคลังตามรายวิชา เพิ่มคำถาม ตรวจคำตอบ และเผยแพร่เมื่อพร้อมใช้งาน" /><AppAlert v-if="message" type="success">{{ message }}</AppAlert><AppAlert v-if="error" type="error">{{ error }}</AppAlert><div class="grid gap-6 xl:grid-cols-2"><section class="card border border-base-300 bg-base-100 shadow-sm"><div class="card-body"><h2 class="card-title">สร้างคลังข้อสอบ</h2><form class="space-y-3" @submit.prevent="createBank"><input v-model="bankForm.name" class="input input-bordered w-full" placeholder="ชื่อคลังข้อสอบ" required /><select v-model="bankForm.subject_id" class="select select-bordered w-full" required><option disabled value="">เลือกรายวิชา</option><option v-for="subject in subjects" :key="subject.id" :value="subject.id">{{ subject.code }} — {{ subject.name }}</option></select><input v-model="bankForm.owner_org_unit_id" class="input input-bordered w-full" placeholder="Org Unit UUID" required /><label class="label cursor-pointer justify-start gap-3"><input v-model="bankForm.is_shared" class="toggle toggle-primary" type="checkbox" /> แชร์คลังข้อสอบ</label><button class="btn btn-primary" type="submit">สร้างคลัง</button></form></div></section><section class="card border border-base-300 bg-base-100 shadow-sm"><div class="card-body"><h2 class="card-title">เพิ่มคำถาม</h2><select v-model="selectedBankId" class="select select-bordered w-full" :disabled="!banks.length"><option disabled value="">เลือกคลังข้อสอบ</option><option v-for="bank in banks" :key="bank.id" :value="bank.id">{{ bank.name }} ({{ bank.status }})</option></select><form v-if="selectedBank" class="mt-3 space-y-3" @submit.prevent="createQuestion"><textarea v-model="questionForm.content" class="textarea textarea-bordered min-h-24 w-full" placeholder="พิมพ์คำถาม" required></textarea><select v-model="questionForm.difficulty" class="select select-bordered w-full"><option value="easy">ง่าย</option><option value="medium">ปานกลาง</option><option value="hard">ยาก</option></select><div v-for="(choice, index) in questionForm.choices" :key="index" class="flex items-center gap-2"><input v-model="choice.content" class="input input-bordered w-full" :placeholder="`ตัวเลือก ${index + 1}`" required /><input v-model="choice.is_correct" class="radio radio-success" type="radio" name="correct-choice" :value="true" aria-label="คำตอบที่ถูกต้อง" /></div><button class="btn btn-secondary" type="submit">เพิ่มคำถาม</button></form><p v-else class="mt-3 text-sm text-base-content/60">สร้างหรือเลือกคลังข้อสอบก่อน</p></div></section></div><section class="mt-6 card border border-base-300 bg-base-100 shadow-sm"><div class="card-body"><div class="flex flex-wrap items-center justify-between gap-3"><h2 class="card-title">คลังข้อสอบและคำถาม</h2><span v-if="selectedBank">{{ questions.length }} คำถาม</span></div><div class="overflow-x-auto"><table class="table"><thead><tr><th>คลัง</th><th>รายวิชา</th><th>สถานะ</th><th>จัดการ</th></tr></thead><tbody><tr v-for="bank in banks" :key="bank.id"><td>{{ bank.name }}</td><td>{{ subjects.find((subject) => subject.id === bank.subject_id)?.name || "-" }}</td><td>{{ bank.status }}</td><td><button v-if="bank.status === 'draft'" class="btn btn-primary btn-xs" type="button" @click="publish(bank.id)">เผยแพร่</button></td></tr></tbody></table></div><div v-if="questions.length" class="mt-4 space-y-2"><article v-for="(question, index) in questions" :key="question.id" class="rounded-box border border-base-300 p-3"><div class="flex justify-between gap-3"><span><b>{{ index + 1 }}.</b> {{ question.content }}</span><span class="badge badge-ghost">{{ question.difficulty }}</span></div><p class="mt-2 text-sm text-base-content/70">{{ question.choices.map((choice) => `${choice.is_correct ? '✓' : '○'} ${choice.content}`).join('   ') }}</p></article></div></div></section></PageContainer></template>
